import React, { useEffect, useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import './AuthPage.css';

function UserIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path
        d="M12 12a4 4 0 1 0 0-8 4 4 0 0 0 0 8z"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
      />
      <path
        d="M4.5 19.2a7.8 7.8 0 0 1 15 0"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinecap="round"
      />
    </svg>
  );
}

function MailIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path
        d="M4 7.5A2.5 2.5 0 0 1 6.5 5h11A2.5 2.5 0 0 1 20 7.5v9a2.5 2.5 0 0 1-2.5 2.5h-11A2.5 2.5 0 0 1 4 16.5v-9z"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
      />
      <path
        d="M5 8l7 5 7-5"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function LockIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <rect
        x="5"
        y="10"
        width="14"
        height="10"
        rx="2.4"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
      />
      <path
        d="M8 10V8a4 4 0 1 1 8 0v2"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinecap="round"
      />
    </svg>
  );
}

export default function SignupPage() {
  const navigate = useNavigate();
  const { signup, isLoggedIn } = useAuth();

  const [form, setForm] = useState({
    name: '',
    nickname: '',
    email: '',
    password: '',
    confirmPassword: '',
    agree: true,
    marketing: false,
  });
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      navigate('/dashboard', { replace: true });
    }
  }, [isLoggedIn, navigate]);

  const helperText = useMemo(() => {
    if (!form.name && !form.nickname) {
      return '이름과 닉네임을 입력하면 캐릭터가 더 자연스럽게 말을 걸어줄 수 있어요.';
    }
    if (form.name && !form.email) {
      return '좋아요. 이제 이메일과 비밀번호를 입력하면 가입 준비가 거의 끝나요.';
    }
    return '가입 후 바로 캐릭터 중심 홈과 대화 페이지로 이동할 수 있어요.';
  }, [form.name, form.nickname, form.email]);

  const updateField = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const validate = () => {
    if (!form.name.trim()) return '이름을 입력해주세요.';
    if (!form.nickname.trim()) return '닉네임을 입력해주세요.';
    if (!form.email.trim()) return '이메일을 입력해주세요.';
    if (!/\S+@\S+\.\S+/.test(form.email)) return '올바른 이메일 형식을 입력해주세요.';
    if (!form.password.trim()) return '비밀번호를 입력해주세요.';
    if (form.password.length < 6) return '비밀번호는 6자 이상 입력해주세요.';
    if (form.password !== form.confirmPassword) return '비밀번호 확인이 일치하지 않아요.';
    if (!form.agree) return '서비스 이용 동의가 필요해요.';
    return '';
  };

  const callSignup = async () => {
    if (typeof signup !== 'function') {
      throw new Error('회원가입 기능이 아직 연결되지 않았어요.');
    }

    const payload = {
      name: form.name,
      nickname: form.nickname,
      email: form.email,
      password: form.password,
      agreeMarketing: form.marketing,
    };

    if (signup.length <= 1) {
      return signup(payload);
    }

    return signup(form.name, form.email, form.password, form.nickname);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const nextError = validate();
    if (nextError) {
      setError(nextError);
      return;
    }

    setError('');
    setSubmitting(true);

    try {
      await callSignup();
      navigate('/dashboard', { replace: true });
    } catch (err) {
      setError(err?.message || '회원가입 중 문제가 발생했어요. 다시 시도해주세요.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section className="matey-auth">
      <div className="matey-auth__container">
        <div className="matey-auth__grid">
          <div className="matey-auth__visual">
            <div className="matey-auth__visual-card">
              <div className="matey-auth__visual-kicker">Create Your Space</div>

              <h1>
                처음이라도 괜찮아요.
                <br />
                <strong>캐릭터와 천천히 친해지는 공간을 만들어요</strong>
              </h1>

              <p>
                회원가입 후에는 토끼와 고양이 캐릭터가 먼저 말을 걸어주고,
                감정 체크인부터 대화까지 자연스럽게 이어져요.
              </p>

              <div className="matey-auth__mascot-stage">
                <div className="matey-auth__mascot-stage-glow matey-auth__mascot-stage-glow--one" />
                <div className="matey-auth__mascot-stage-glow matey-auth__mascot-stage-glow--two" />

                <div className="matey-auth__mascot-image matey-auth__mascot-image--single">
                  <img src="/images/rabbit.png" alt="토끼 캐릭터" />
                </div>

                <div className="matey-auth__bubble">
                  <strong>하루</strong>
                  <p>가입만 하면 오늘 상태를 먼저 물어보고, 당신에게 맞는 흐름으로 안내해드릴게요.</p>
                </div>
              </div>

              <div className="matey-auth__tips">
                <span>개인화 시작</span>
                <span>감정 체크인</span>
                <span>캐릭터 대화</span>
              </div>
            </div>
          </div>

          <div className="matey-auth__form-shell">
            <div className="matey-auth__card">
              <div className="matey-auth__tabs">
                <Link to="/login" className="matey-auth__tab">
                  로그인
                </Link>
                <Link to="/signup" className="matey-auth__tab is-active">
                  회원가입
                </Link>
              </div>

              <div className="matey-auth__header">
                <span className="matey-auth__badge">New Account</span>
                <h2>회원가입</h2>
                <p>간단한 정보만 입력하면 바로 캐릭터 중심 감정 케어 경험을 시작할 수 있어요.</p>
              </div>

              <form className="matey-auth__form" onSubmit={handleSubmit}>
                <div className="matey-auth__split">
                  <label className="matey-auth__field">
                    <span>이름</span>
                    <div className="matey-auth__input-wrap">
                      <i>
                        <UserIcon />
                      </i>
                      <input
                        type="text"
                        value={form.name}
                        onChange={(e) => updateField('name', e.target.value)}
                        placeholder="홍길동"
                        autoComplete="name"
                      />
                    </div>
                  </label>

                  <label className="matey-auth__field">
                    <span>닉네임</span>
                    <div className="matey-auth__input-wrap">
                      <i>
                        <UserIcon />
                      </i>
                      <input
                        type="text"
                        value={form.nickname}
                        onChange={(e) => updateField('nickname', e.target.value)}
                        placeholder="하루와 대화하는 나"
                      />
                    </div>
                  </label>
                </div>

                <label className="matey-auth__field">
                  <span>이메일</span>
                  <div className="matey-auth__input-wrap">
                    <i>
                      <MailIcon />
                    </i>
                    <input
                      type="email"
                      value={form.email}
                      onChange={(e) => updateField('email', e.target.value)}
                      placeholder="you@example.com"
                      autoComplete="email"
                    />
                  </div>
                </label>

                <div className="matey-auth__split">
                  <label className="matey-auth__field">
                    <span>비밀번호</span>
                    <div className="matey-auth__input-wrap">
                      <i>
                        <LockIcon />
                      </i>
                      <input
                        type="password"
                        value={form.password}
                        onChange={(e) => updateField('password', e.target.value)}
                        placeholder="6자 이상 입력"
                        autoComplete="new-password"
                      />
                    </div>
                  </label>

                  <label className="matey-auth__field">
                    <span>비밀번호 확인</span>
                    <div className="matey-auth__input-wrap">
                      <i>
                        <LockIcon />
                      </i>
                      <input
                        type="password"
                        value={form.confirmPassword}
                        onChange={(e) => updateField('confirmPassword', e.target.value)}
                        placeholder="한 번 더 입력"
                        autoComplete="new-password"
                      />
                    </div>
                  </label>
                </div>

                <div className="matey-auth__helper">
                  <strong>현재 안내</strong>
                  <p>{helperText}</p>
                </div>

                <div className="matey-auth__checks">
                  <label className="matey-auth__check">
                    <input
                      type="checkbox"
                      checked={form.agree}
                      onChange={(e) => updateField('agree', e.target.checked)}
                    />
                    <span>서비스 이용약관 및 개인정보 처리방침에 동의합니다.</span>
                  </label>

                  <label className="matey-auth__check">
                    <input
                      type="checkbox"
                      checked={form.marketing}
                      onChange={(e) => updateField('marketing', e.target.checked)}
                    />
                    <span>업데이트 및 혜택 소식을 받아볼게요. (선택)</span>
                  </label>
                </div>

                {error && <div className="matey-auth__error">{error}</div>}

                <button
                  type="submit"
                  className="matey-auth__submit"
                  disabled={submitting}
                >
                  {submitting ? '가입 중...' : '회원가입하고 시작하기'}
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
